57	describe("MHPCO Claim Office - Claim Processing", () => {
58	  it("should apply 100 G deductible per damage event (sword damage 500 G: payout 400 G)", () => {
59	    expect(processClaim([{ type: "Sword" }], [500])).toBe(400);
60	  });
61	  it("should fully reimburse damage for dragon material items (dragon sword damage 1000 G: payout 1000 G - no deductible)", () => {
