84	  it("should calculate base premium for single rune component (25 G premium per component)", () => {
85	    expect(calculatePremium([{ type: "Rune" }])).toBe(30);
86	  });
87	  it("should calculate base premium for single moonstone component (25 G premium per component)", () => {
88	    expect(calculatePremium([{ type: "Moonstone" }])).toBe(30);
89	  });
90	  it("should apply special block pricing for exactly 3 identical components (3 runes: 60 G base premium instead of 75 G)", () => {
91	    expect(calculatePremium([{ type: "Rune" }, { type: "Rune" }, { type: "Rune" }])).toBe(65);
92	  });
