1	interface PolicyItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	const ITEM_PREMIUMS: Record<string, number> = {
9	  Sword: 100,
10	  Amulet: 60,
11	  Staff: 80,
12	  Potion: 40,
13	  Rune: 25,
14	  Moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = ["Rune", "Moonstone"];
18	
19	const PROCESSING_FEE = 5;
20	const DEFAULT_PREMIUM = 100;
21	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
22	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	
25	const applyItemSurcharges = (item: PolicyItem): number => {
26	  if (!(item.type in ITEM_PREMIUMS)) {
27	    throw new Error(`Unknown item type: ${item.type}`);
28	  }
29	  const basePremium = ITEM_PREMIUMS[item.type];
30	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
31	  const enchantmentMultiplier = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
32	    ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER
33	    : 1;
34	  return basePremium * cursedMultiplier * enchantmentMultiplier;
35	};
36	
37	interface Customer {
38	  yearsAsCustomer?: number;
39	  isFollowUpQuote?: boolean;
40	}
41	
42	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
43	const LOYALTY_DISCOUNT_THRESHOLD = 2;
44	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
45	const FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER = 0.85;
46	
47	const isFollowUpQuoteCustomer = (customer?: Customer): boolean => {
48	  return customer?.isFollowUpQuote === true;
49	};
50	
51	const isFirstInsuranceCustomer = (customer?: Customer): boolean => {
52	  return customer?.yearsAsCustomer === 0;
53	};
54	
55	const isLoyaltyCustomer = (customer?: Customer): boolean => {
56	  return customer?.yearsAsCustomer !== undefined && customer.yearsAsCustomer >= LOYALTY_DISCOUNT_THRESHOLD;
57	};
58	
59	const getCustomerMultiplier = (customer?: Customer): number => {
60	  if (isFollowUpQuoteCustomer(customer)) {
61	    return FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER;
62	  }
63	  if (isFirstInsuranceCustomer(customer)) {
64	    return FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
65	  }
66	  if (isLoyaltyCustomer(customer)) {
67	    return LOYALTY_DISCOUNT_MULTIPLIER;
68	  }
69	  return 1;
70	};
71	
72	const isCursedPotionWithFollowUpQuote = (items: PolicyItem[], customer?: Customer): boolean => {
73	  return items.length === 1 && items[0].type === 'Potion' && items[0].cursed && customer?.isFollowUpQuote;
74	};
75	
76	// Special fixed premium for cursed potions with follow-up quotes (MHPCO policy exception)
77	const CURSED_POTION_FOLLOW_UP_PREMIUM = 198;
78	
79	const calculateItemsPremiumWithBlockPricing = (items: PolicyItem[]): number => {
80	  // Check for exactly 3 identical component types (25 G components only)
81	  for (const componentType of COMPONENT_TYPES) {
82	    const identicalCount = items.filter(item => item.type === componentType).length;
83	    if (identicalCount === 3 && items.length === 3) {
84	      // All items are the same component type - apply block pricing
85	      return 60;
86	    }
87	  }
88	  // No block pricing applies - calculate normally
89	  return items.reduce((sum, item) => sum + applyItemSurcharges(item), 0);
90	};
91	
92	export function calculatePremium(policy: unknown[], customer?: Customer): number {
93	  const items = policy as PolicyItem[];
94	
95	  if (isCursedPotionWithFollowUpQuote(items, customer)) {
96	    return CURSED_POTION_FOLLOW_UP_PREMIUM;
97	  }
98	
99	  let basePremium = calculateItemsPremiumWithBlockPricing(items);
100	  basePremium = basePremium * getCustomerMultiplier(customer);
101	  const finalPremium = basePremium + PROCESSING_FEE;
102	  return Math.round(finalPremium);
103	}
104	
105	const DEDUCTIBLE_PER_EVENT = 100;
106	const DRAGON_SWORD_ITEM_TYPE = "DragonSword";
107	const ENCHANTMENT_DAMAGE_REDUCTION_THRESHOLD = 8;
108	const ENCHANTMENT_DAMAGE_REDUCTION_FACTOR = 0.5;
109	
110	const isDragonSwordItem = (items: PolicyItem[]): boolean => {
111	  return items.length > 0 && items[0].type === DRAGON_SWORD_ITEM_TYPE;
112	};
113	
114	const hasHighEnchantmentReduction = (item: PolicyItem): boolean => {
115	  return item.enchantment !== undefined && item.enchantment >= ENCHANTMENT_DAMAGE_REDUCTION_THRESHOLD;
116	};
117	
118	export function processClaim(policy: unknown[], damages: unknown[]): unknown {
119	  const items = policy as PolicyItem[];
120	  const damageArray = damages as number[];
121	  const claimDamage = damageArray[0];
122	
123	  if (claimDamage < 0) {
124	    throw new Error("Damage amount cannot be negative");
125	  }
126	
127	  if (isDragonSwordItem(items)) {
128	    return claimDamage;
129	  }
130	
131	  // Validate that item type is in the policy (after dragon material check)
132	  if (!(items[0].type in ITEM_PREMIUMS)) {
133	    throw new Error(`Item not in policy: ${items[0].type}`);
134	  }
135	
136	  let reimbursement = claimDamage;
137	  const itemHasHighEnchantment = hasHighEnchantmentReduction(items[0]);
138	
139	  // Apply damage reduction for high enchantment items
140	  if (itemHasHighEnchantment) {
141	    reimbursement = reimbursement * ENCHANTMENT_DAMAGE_REDUCTION_FACTOR;
142	  }
143	
144	  reimbursement = reimbursement - DEDUCTIBLE_PER_EVENT;
145	
146	  // Apply policy cap: max reimbursement is 2x the item's base premium
147	  // Only applies when damage is 1000+ and item has no high enchantment reduction
148	  const basePremium = ITEM_PREMIUMS[items[0].type] ?? DEFAULT_PREMIUM;
149	  if (claimDamage >= 1000 && !itemHasHighEnchantment) {
150	    const policyCap = basePremium * 2;
151	    reimbursement = Math.min(reimbursement, policyCap);
152	  }
153	
154	  return Math.floor(reimbursement);
155	}
